longest-substring-without-repeating-characters.c<pre><code>int lengthOfLongestSubstring(char* s) {
    int letter[128];
    int max = 0, left = 0, right = -1;
    memset(letter, 0, 128 * sizeof(int));
    while (1) {
        while (!letter[s[++right]] &amp;&amp; s[right]) {
            letter[s[right]] = 1;
        }
        max = (max &gt; right - left) ? max : right - left;
        if (!s[right]) {
            break;
        }
        while (s[left++] != s[right]) {
            letter[s[left - 1]] = 0;
        }
    }
    return max;
}
