void sortColors(int* nums, int numsSize) {
    int zero = 0, two = numsSize - 1;
    for (int i = 0; i &lt;= two; i++) {
        if (nums[i] == 0) {
            swap(nums + i, nums + zero);
            zero++;
        } else if (nums[i] == 2) {
            swap(nums + i, nums + two);
            two--;
            i--;
        }
    }
}
