largest-rectangle-in-histogram.c<pre><code>#define max(a, b) ((b) &gt; (a) ? (b) : (a))

int largestRectangleArea(int* heights, int heightsSize) {
    int* stack = malloc((heightsSize + 5) * sizeof(int));
    int maxSize = 0;
    int index = 0;
    stack[0] = -1;
    for (int i = 0; i &lt;= heightsSize; i++) {
        int h = i &lt; heightsSize ? heights[i] : 0;
        while (stack[index] &gt;= 0 &amp;&amp; h &lt; heights[stack[index]]) {
            int high = heights[stack[index]];
            maxSize = max(maxSize, high * (i - stack[index - 1] - 1));
            index--;
        }
        stack[++index] = i;
    }
    return maxSize;
}
</code></pre> <p>观察代码的小巧思：我们对首尾各增加一个高度为 0 的柱子，方便入栈弹栈。</p>

best-time-to-buy-and-sell-stock.c<pre><code>#define max(a, b) ((b) &gt; (a) ? (b) : (a))
#define min(a, b) ((b) &lt; (a) ? (b) : (a))

int maxProfit(int* prices, int pricesSize) {
    int maxProfit = 0, minPrice = prices[0];
