intersection-of-two-linked-lists.c<pre><code>/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     struct ListNode *next;
 * };
 */
struct ListNode* getIntersectionNode(struct ListNode* headA, struct ListNode* headB) {
    int m = 1, n = 1;
    struct ListNode* a = headA;
    struct ListNode* b = headB;
    while (a-&gt;next != NULL) {
        a = a-&gt;next;
        m++;
    }
    while (b-&gt;next != NULL) {
        b = b-&gt;next;
        n++;
    }
    a = headA, b = headB;
    while (m &gt; n) {
        a = a-&gt;next;
        m--;
    }
    while (n &gt; m) {
        b = b-&gt;next;
        n--;
    }
    do {
        if (a == b) {
            return a;
        }
        a = a-&gt;next;
        b = b-&gt;next;
    } while (a != NULL);
    return NULL;
}
</code></pre>

intersection-of-two-linked-lists.c<pre><code>struct HashTable {
    struct ListNode *key;
    UT_hash_handle hh;
};

struct ListNode *getIntersectionNode(struct ListNode *headA, struct ListNode *headB) {
    struct HashTable *hashTable = NULL;
    struct ListNode *temp = headA;
    while (temp != NULL) {
        struct HashTable *tmp;
        HASH_FIND(hh, hashTable, &amp;temp, sizeof(struct HashTable *), tmp);
        if (tmp == NULL) {
            tmp = malloc(sizeof(struct HashTable));
            tmp-&gt;key = temp;
            HASH_ADD(hh, hashTable, key, sizeof(struct HashTable *), tmp);
        }
        temp = temp-&gt;next;
    }
    temp = headB;
    while (temp != NULL) {
        struct HashTable *tmp;
        HASH_FIND(hh, hashTable, &amp;temp, sizeof(struct HashTable *), tmp);
        if (tmp != NULL) {
            return temp;
        }
        temp = temp-&gt;next;
    }
    return NULL;
}

