kth-largest-element-in-an-array.c<pre><code>void swap(int* a, int* b) {
    int t = *a;
    *a = *b, *b = t;
}

int quickSort(int* nums, int k, int left, int right) {
    int num = nums[(left + right) / 2];
    swap(nums + (left + right) / 2, nums + right);
    int index = -1;
    int sameNum = 1;
    for (int i = left; i &lt; right; i++) {
        if (nums[i] == num) {
            sameNum++;
        }
        if (nums[i] &lt;= num &amp;&amp; index &lt; 0) {
            index = i;
        }
        if (nums[i] &gt; num &amp;&amp; index &gt;= 0) {
            swap(nums + index, nums + i);
            index++;
        }
    }
    index = (index == -1) ? right : index;
    swap(nums + index, nums + right);
    if (k &gt;= index + 1 &amp;&amp; k &lt;= index + sameNum) {
        return num;
    }
    if (k &lt;= index) {
        return quickSort(nums, k, left, index - 1);
    } else {
        return quickSort(nums, k, index + 1, right);
    }
}

int findKthLargest(int* nums, int numsSize, int k) {
    return quickSort(nums, k, 0, numsSize - 1);
}
</code></pre> <p>关于代码：</p> <ul> <li>小优化：考虑到可能存在大量相同元素，由于快排思想会将相同元素集中到一边，这会让我们选取的子数组缩小幅度很低，极大影响算法效率（时间复杂度容易陷入 \(O(n^2)\))，因此引入 <code>sameNum</code>，快速判断相同元素。</li> <li>易错：对 <code>sameNum</code> 的更新应在 <code>swap</code> 之前，避免重复判断。</li> <li>易错：注意对 <code>index</code> 的维护，即对于初始化值 <code>-1</code> 的更新。</li> </ul>

sum-of-root-to-leaf-binary-numbers.c<pre><code>/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     struct TreeNode *left;
 *     struct TreeNode *right;
 * };
 */

int isLeaf(struct TreeNode* node) {
    return node-&gt;left == NULL &amp;&amp; node-&gt;right == NULL;
}

int sum = 0;

void addSum(struct TreeNode* node, int val) {
    if (!isLeaf(node)) {
        if (node-&gt;left != NULL) {
            addSum(node-&gt;left, val * 2 + node-&gt;left-&gt;val);
        }
        if (node-&gt;right != NULL) {
            addSum(node-&gt;right, val * 2 + node-&gt;right-&gt;val);
        }
    } else {
        sum = sum + val;
    }
}

int sumRootToLeaf(struct TreeNode* root) {
    struct TreeNode* node = root;
    addSum(node, node-&gt;val);
    return sum;
}
</code></pre>

